/** Look up coordinates for a CF datacenter code. Returns null for unknown colos. */
export function coloToLatLon(colo: string): { lat: number; lon: number; city: string } | null {
  return COLO_COORDINATES[colo.toUpperCase()] ?? null;
}

/** All known datacenter codes. */
export const KNOWN_COLOS = Object.keys(COLO_COORDINATES);
